module eeprom_cell (
    input [4:0] data_in,
    input write,
    output reg [4:0] data_out
);
  wire [4:0] _tap_data_in = data_in & {5{1'b1}};

    always @(*) begin
        if (write) begin
            data_out = data_in; // Write data to EEPROM
        end
        // else retain previous value
    end
endmodule
